SELECT tnf.fbill_no, tnf.fdocument_status, su.user_name as fapprover_id, tnf.fapprove_date, sys.user_name as fmodifier_id, tnf.fcreate_date, sysu.user_name as fcreator_id, tnf.fmodify_date, tnf.fcancel_date, tnf.fcanceler, tnf.fbill_type_id, tnf.fbusiness_type, tnf.fdate, bym.number as fmaterial_id, tnf.fmaterial_name, tnf.fmaterial_model, byd.name as funit_id, bydy.name as fbase_unit_id, tnf.finspect_qty, tnf.fqualified_qty, tnf.funqualified_qty, tnf.finspect_result, tnf.fqc_status, super.name as fsupplier_id, tnf.fstock_id, tnf.flot, tnf.fzxs, tnf.fmz, tnf.fjz, tnf.fchang, tnf.fkuan, tnf.fgao, tnf.fzxshu, tnf.ftj, tnf.fdiscount_qty, tnf.fmzh, tnf.fbzyq, tnf.ftsyq, tnf.fcptp, tnf.fxsddh, tnf.fcgddh, tnf.fkhjc, tnf.f_cty_picture, tnf.f_cty_picture1, tnf.f_peuu_attachment_ca9, tnf.fnhc, tnf.fnhk, tnf.fnhg FROM receipt_notice_full tnf LEFT JOIN sys_user su on tnf.fapprover_id=su.k3_key LEFT JOIN sys_user sys on tnf.fmodifier_id=sys.k3_key LEFT JOIN sys_user sysu on tnf.fcreator_id=sysu.k3_key LEFT JOIN supplier super on tnf.fsupplier_id=super.supplierid LEFT JOIN by_material bym on tnf.fmaterial_id=bym.k3_id LEFT JOIN bymaterial_dictionary byd on tnf.funit_id=byd.kingdee and byd.category='unit' LEFT JOIN bymaterial_dictionary bydy on tnf.fbase_unit_id=byd.kingdee and bydy.category='unit'
AND tnf.fbill_no LIKE CONCAT('%', #{receiptNoticeFull.fBillNo}, '%')
AND tnf.fdocument_status = #{receiptNoticeFull.fDocumentStatus}
AND tnf.fbill_type_id = #{receiptNoticeFull.fBillTypeId}
AND tnf.fbusiness_type = #{receiptNoticeFull.fBusinessType}
AND DATE(tnf.fdate) = DATE(#{receiptNoticeFull.fDate})
AND tnf.fmaterial_id = #{receiptNoticeFull.fMaterialId}
AND tnf.fsupplier_id = #{receiptNoticeFull.fSupplierId}
AND tnf.fkhjc = #{receiptNoticeFull.fKhjc}
AND tnf.fxsddh = #{receiptNoticeFull.fXsddh}
AND tnf.fcgddh = #{receiptNoticeFull.fCgddh}
ORDER BY tnf.fcreate_date DESC LIMIT #{offset}, #{pageSize}

SELECT tnf.fbill_no, tnf.fdocument_status, su.user_name as fapprover_id, tnf.fapprove_date, sys.user_name as fmodifier_id, tnf.fcreate_date, sysu.user_name as fcreator_id, tnf.fmodify_date, tnf.fcancel_date, tnf.fcanceler, tnf.fbill_type_id, tnf.fbusiness_type, tnf.fdate, tnf.fmaterial_id, tnf.fmaterial_name, tnf.fmaterial_model, tnf.funit_id, tnf.fbase_unit_id, tnf.finspect_qty, tnf.fqualified_qty, tnf.funqualified_qty, tnf.finspect_result, tnf.fqc_status, tnf.fsupplier_id, tnf.fstock_id, tnf.flot, tnf.fzxs, tnf.fmz, tnf.fjz, tnf.fchang, tnf.fkuan, tnf.fgao, tnf.fzxshu, tnf.ftj, tnf.fdiscount_qty, tnf.fmzh, tnf.fbzyq, tnf.ftsyq, tnf.fcptp, tnf.fxsddh, tnf.fcgddh, tnf.fkhjc, tnf.f_cty_picture, tnf.f_cty_picture1, tnf.f_peuu_attachment_ca9, tnf.fnhc, tnf.fnhk, tnf. fnhg FROM receipt_notice_full tnf
LEFT JOIN sys_user su on tnf.fapprover_id=su.k3_key LEFT JOIN sys_user sys on tnf.fmodifier_id=sys.k3_key LEFT JOIN sys_user sysu on tnf.fcreator_id=sysu.k3_key
WHERE tnf.fbill_no = #{fBillNo}
